43: import static org.apache.kafka.common.record.internal.Records.LOG_OVERHEAD;
44: 
45: /**
46:  * RecordBatch implementation for magic 2 and above. The schema is given below:
47:  *
48:  * RecordBatch =>
49:  *  BaseOffset => Int64
50:  *  Length => Int32
51:  *  PartitionLeaderEpoch => Int32
52:  *  Magic => Int8
53:  *  CRC => Uint32
54:  *  Attributes => Int16
55:  *  LastOffsetDelta => Int32 // also serves as LastSequenceDelta
56:  *  BaseTimestamp => Int64
57:  *  MaxTimestamp => Int64
58:  *  ProducerId => Int64
59:  *  ProducerEpoch => Int16
60:  *  BaseSequence => Int32
61:  *  RecordsCount => Int32
62:  *  Records => [Record]
63:  *
64:  * Note that when compression is enabled (see attributes below), the compressed record data is serialized
65:  * directly following the count of the number of records.
66:  *
67:  * The CRC covers the data from the attributes to the end of the batch (i.e. all the bytes that follow the CRC). It is
68:  * located after the magic byte, which means that clients must parse the magic byte before deciding how to interpret
69:  * the bytes between the batch length and the magic byte. The partition leader epoch field is not included in the CRC
70:  * computation to avoid the need to recompute the CRC when this field is assigned for every batch that is received by
71:  * the broker. The CRC-32C (Castagnoli) polynomial is used for the computation.
72:  *
73:  * On Compaction: Unlike the older message formats, magic v2 and above preserves the first and last offset/sequence
74:  * numbers from the original batch when the log is cleaned. This is required in order to be able to restore the
75:  * producer's state when the log is reloaded. If we did not retain the last sequence number, then following
76:  * a partition leader failure, once the new leader has rebuilt the producer state from the log, the next sequence
77:  * expected number would no longer be in sync with what was written by the client. This would cause an
78:  * unexpected OutOfOrderSequence error, which is typically fatal. The base sequence number must be preserved for
79:  * duplicate checking: the broker checks incoming Produce requests for duplicates by verifying that the first and
80:  * last sequence numbers of the incoming batch match the last from that producer.
81:  *
82:  * Note that if all of the records in a batch are removed during compaction, the broker may still retain an empty
83:  * batch header in order to preserve the producer sequence information as described above. These empty batches
84:  * are retained only until either a new sequence number is written by the corresponding producer or the producerId
85:  * is expired from lack of activity.
86:  *
87:  * There is no similar need to preserve the timestamp from the original batch after compaction. The BaseTimestamp
88:  * field therefore reflects the timestamp of the first record in the batch in most cases. If the batch is empty, the
89:  * BaseTimestamp will be set to -1 (NO_TIMESTAMP). If the delete horizon flag is set to 1, the BaseTimestamp
90:  * will be set to the time at which tombstone records and aborted transaction markers in the batch should be removed.
91:  *
92:  * Similarly, the MaxTimestamp field reflects the maximum timestamp of the current records if the timestamp type
93:  * is CREATE_TIME. For LOG_APPEND_TIME, on the other hand, the MaxTimestamp field reflects the timestamp set
94:  * by the broker and is preserved after compaction. Additionally, the MaxTimestamp of an empty batch always retains
95:  * the previous value prior to becoming empty.
96:  *
97:  * The current attributes are given below:
98:  *
99:  *  ---------------------------------------------------------------------------------------------------------------------------
100:  *  | Unused (7-15) | Delete Horizon Flag (6) | Control (5) | Transactional (4) | Timestamp Type (3) | Compression Type (0-2) |
101:  *  ---------------------------------------------------------------------------------------------------------------------------
102:  */
103: public class DefaultRecordBatch extends AbstractRecordBatch implements MutableRecordBatch {
104:     static final int BASE_OFFSET_OFFSET = 0;
105:     static final int BASE_OFFSET_LENGTH = 8;
106:     static final int LENGTH_OFFSET = BASE_OFFSET_OFFSET + BASE_OFFSET_LENGTH;
107:     static final int LENGTH_LENGTH = 4;
108:     static final int PARTITION_LEADER_EPOCH_OFFSET = LENGTH_OFFSET + LENGTH_LENGTH;
109:     static final int PARTITION_LEADER_EPOCH_LENGTH = 4;
110:     static final int MAGIC_OFFSET = PARTITION_LEADER_EPOCH_OFFSET + PARTITION_LEADER_EPOCH_LENGTH;
111:     static final int MAGIC_LENGTH = 1;
112:     public static final int CRC_OFFSET = MAGIC_OFFSET + MAGIC_LENGTH;
113:     static final int CRC_LENGTH = 4;
114:     static final int ATTRIBUTES_OFFSET = CRC_OFFSET + CRC_LENGTH;
115:     static final int ATTRIBUTE_LENGTH = 2;
116:     public static final int LAST_OFFSET_DELTA_OFFSET = ATTRIBUTES_OFFSET + ATTRIBUTE_LENGTH;
117:     static final int LAST_OFFSET_DELTA_LENGTH = 4;
118:     static final int BASE_TIMESTAMP_OFFSET = LAST_OFFSET_DELTA_OFFSET + LAST_OFFSET_DELTA_LENGTH;
119:     static final int BASE_TIMESTAMP_LENGTH = 8;
120:     static final int MAX_TIMESTAMP_OFFSET = BASE_TIMESTAMP_OFFSET + BASE_TIMESTAMP_LENGTH;
121:     static final int MAX_TIMESTAMP_LENGTH = 8;
122:     static final int PRODUCER_ID_OFFSET = MAX_TIMESTAMP_OFFSET + MAX_TIMESTAMP_LENGTH;
123:     static final int PRODUCER_ID_LENGTH = 8;
124:     static final int PRODUCER_EPOCH_OFFSET = PRODUCER_ID_OFFSET + PRODUCER_ID_LENGTH;
125:     static final int PRODUCER_EPOCH_LENGTH = 2;
126:     static final int BASE_SEQUENCE_OFFSET = PRODUCER_EPOCH_OFFSET + PRODUCER_EPOCH_LENGTH;
127:     static final int BASE_SEQUENCE_LENGTH = 4;
128:     public static final int RECORDS_COUNT_OFFSET = BASE_SEQUENCE_OFFSET + BASE_SEQUENCE_LENGTH;
129:     static final int RECORDS_COUNT_LENGTH = 4;
130:     static final int RECORDS_OFFSET = RECORDS_COUNT_OFFSET + RECORDS_COUNT_LENGTH;
131:     public static final int RECORD_BATCH_OVERHEAD = RECORDS_OFFSET;
132: 
133:     private static final byte COMPRESSION_CODEC_MASK = 0x07;
134:     private static final byte TRANSACTIONAL_FLAG_MASK = 0x10;
135:     private static final int CONTROL_FLAG_MASK = 0x20;
136:     private static final byte DELETE_HORIZON_FLAG_MASK = 0x40;
137:     private static final byte TIMESTAMP_TYPE_MASK = 0x08;
138: 
139:     private final ByteBuffer buffer;
140: 
141:     DefaultRecordBatch(ByteBuffer buffer) {
142:         this.buffer = buffer;
143:     }
144: 
145:     @Override
146:     public byte magic() {
147:         return buffer.get(MAGIC_OFFSET);
148:     }
149: 
150:     @Override
151:     public void ensureValid() {
152:         if (sizeInBytes() < RECORD_BATCH_OVERHEAD)
153:             throw new CorruptRecordException("Record batch is corrupt (the size " + sizeInBytes() +
154:                     " is smaller than the minimum allowed overhead " + RECORD_BATCH_OVERHEAD + ")");
155: 
156:         if (!isValid())
157:             throw new CorruptRecordException("Record is corrupt (stored crc = " + checksum()
158:                     + ", computed crc = " + computeChecksum() + ")");
159:     }
160: 
161:     /**
162:      * Gets the base timestamp of the batch which is used to calculate the record timestamps from the deltas.
163:      *
164:      * @return The base timestamp
165:      */
166:     public long baseTimestamp() {
167:         return buffer.getLong(BASE_TIMESTAMP_OFFSET);
168:     }
169: 
170:     @Override
171:     public long maxTimestamp() {
172:         return buffer.getLong(MAX_TIMESTAMP_OFFSET);
173:     }
174: 
175:     @Override
176:     public TimestampType timestampType() {
177:         return (attributes() & TIMESTAMP_TYPE_MASK) == 0 ? TimestampType.CREATE_TIME : TimestampType.LOG_APPEND_TIME;
178:     }
179: 
180:     @Override
181:     public long baseOffset() {
182:         return buffer.getLong(BASE_OFFSET_OFFSET);
183:     }
184: 
185:     @Override
186:     public long lastOffset() {
187:         return baseOffset() + lastOffsetDelta();
188:     }
189: 
190:     @Override
191:     public long producerId() {
192:         return buffer.getLong(PRODUCER_ID_OFFSET);
193:     }
194: 
195:     @Override
196:     public short producerEpoch() {
197:         return buffer.getShort(PRODUCER_EPOCH_OFFSET);
198:     }
199: 
200:     @Override
201:     public int baseSequence() {
202:         return buffer.getInt(BASE_SEQUENCE_OFFSET);
203:     }
204: 
205:     private int lastOffsetDelta() {
206:         return buffer.getInt(LAST_OFFSET_DELTA_OFFSET);
207:     }
208: 
209:     @Override
210:     public int lastSequence() {
211:         int baseSequence = baseSequence();
212:         if (baseSequence == RecordBatch.NO_SEQUENCE)
213:             return RecordBatch.NO_SEQUENCE;
214:         return incrementSequence(baseSequence, lastOffsetDelta());
215:     }
216: 
217:     @Override
218:     public CompressionType compressionType() {
219:         return CompressionType.forId(attributes() & COMPRESSION_CODEC_MASK);
220:     }
221: 
222:     @Override
223:     public int sizeInBytes() {
224:         return LOG_OVERHEAD + buffer.getInt(LENGTH_OFFSET);
225:     }
226: 
227:     private int count() {
228:         return buffer.getInt(RECORDS_COUNT_OFFSET);
229:     }
230: 
231:     @Override
232:     public Integer countOrNull() {
233:         return count();
234:     }
235: 
236:     @Override
237:     public void writeTo(ByteBuffer buffer) {
238:         buffer.put(this.buffer.duplicate());
239:     }
240: 
241:     @Override
242:     public void writeTo(ByteBufferOutputStream outputStream) {
243:         outputStream.write(this.buffer.duplicate());
244:     }
245: 
246:     @Override
247:     public boolean isTransactional() {
248:         return (attributes() & TRANSACTIONAL_FLAG_MASK) > 0;
249:     }
250: 
251:     private boolean hasDeleteHorizonMs() {
252:         return (attributes() & DELETE_HORIZON_FLAG_MASK) > 0;
253:     }
254: 
255:     @Override
256:     public OptionalLong deleteHorizonMs() {
257:         if (hasDeleteHorizonMs())
258:             return OptionalLong.of(buffer.getLong(BASE_TIMESTAMP_OFFSET));
259:         else
260:             return OptionalLong.empty();
261:     }
262: 
263:     @Override
264:     public boolean isControlBatch() {
265:         return (attributes() & CONTROL_FLAG_MASK) > 0;
266:     }
267: 
268:     @Override
269:     public int partitionLeaderEpoch() {
270:         return buffer.getInt(PARTITION_LEADER_EPOCH_OFFSET);
271:     }
272: 
273:     public InputStream recordInputStream(BufferSupplier bufferSupplier) {
274:         final ByteBuffer buffer = this.buffer.duplicate();
275:         buffer.position(RECORDS_OFFSET);
276:         return Compression.of(compressionType()).build().wrapForInput(buffer, magic(), bufferSupplier);
277:     }
278: 
279:     private CloseableIterator<Record> compressedIterator(BufferSupplier bufferSupplier, boolean skipKeyValue) {
280:         final InputStream inputStream = recordInputStream(bufferSupplier);
281: 
282:         if (skipKeyValue) {
283:             return new StreamRecordIterator(inputStream) {
284:                 @Override
285:                 protected Record doReadRecord(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) throws IOException {
286:                     return DefaultRecord.readPartiallyFrom(inputStream, baseOffset, baseTimestamp, baseSequence, logAppendTime);
287:                 }
288:             };
289:         } else {
290:             return new StreamRecordIterator(inputStream) {
291:                 @Override
292:                 protected Record doReadRecord(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) throws IOException {
293:                     return DefaultRecord.readFrom(inputStream, baseOffset, baseTimestamp, baseSequence, logAppendTime);
294:                 }
295:             };
296:         }
297:     }
298: 
299:     private CloseableIterator<Record> uncompressedIterator() {
300:         final ByteBuffer buffer = this.buffer.duplicate();
301:         buffer.position(RECORDS_OFFSET);
302:         return new RecordIterator() {
303:             @Override
304:             protected Record readNext(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) {
305:                 try {
306:                     return DefaultRecord.readFrom(buffer, baseOffset, baseTimestamp, baseSequence, logAppendTime);
307:                 } catch (BufferUnderflowException e) {
308:                     throw new InvalidRecordException("Incorrect declared batch size, premature EOF reached");
309:                 }
310:             }
311:             @Override
312:             protected boolean ensureNoneRemaining() {
313:                 return !buffer.hasRemaining();
314:             }
315:             @Override
316:             public void close() {}
317:         };
318:     }
319: 
320:     @Override
321:     public Iterator<Record> iterator() {
322:         if (count() == 0)
323:             return Collections.emptyIterator();
324: 
325:         if (!isCompressed())
326:             return uncompressedIterator();
327: 
328:         // for a normal iterator, we cannot ensure that the underlying compression stream is closed,
329:         // so we decompress the full record set here. Use cases which call for a lower memory footprint
330:         // can use `streamingIterator` at the cost of additional complexity
331:         try (CloseableIterator<Record> iterator = compressedIterator(BufferSupplier.NO_CACHING, false)) {
332:             List<Record> records = new ArrayList<>(count());
333:             while (iterator.hasNext())
334:                 records.add(iterator.next());
335:             return records.iterator();
336:         }
337:     }
338: 
339:     @Override
340:     public CloseableIterator<Record> skipKeyValueIterator(BufferSupplier bufferSupplier) {
341:         if (count() == 0) {
342:             return CloseableIterator.wrap(Collections.emptyIterator());
343:         }
344: 
345:         /*
346:          * For uncompressed iterator, it is actually not worth skipping key / value / headers at all since
347:          * its ByteBufferInputStream's skip() function is less efficient compared with just reading it actually
348:          * as it will allocate new byte array.
349:          */
350:         if (!isCompressed())
351:             return uncompressedIterator();
352: 
353:         // we define this to be a closable iterator so that caller (i.e. the log validator) needs to close it
354:         // while we can save memory footprint of not decompressing the full record set ahead of time
355:         return compressedIterator(bufferSupplier, true);
356:     }
357: 
358:     @Override
359:     public CloseableIterator<Record> streamingIterator(BufferSupplier bufferSupplier) {
360:         if (isCompressed())
361:             return compressedIterator(bufferSupplier, false);
362:         else
363:             return uncompressedIterator();
364:     }
365: 
366:     @Override
367:     public void setLastOffset(long offset) {
368:         buffer.putLong(BASE_OFFSET_OFFSET, offset - lastOffsetDelta());
369:     }
370: 
371:     @Override
372:     public void setMaxTimestamp(TimestampType timestampType, long maxTimestamp) {
373:         long currentMaxTimestamp = maxTimestamp();
374:         // We don't need to recompute crc if the timestamp is not updated.
375:         if (timestampType() == timestampType && currentMaxTimestamp == maxTimestamp)
376:             return;
377: 
378:         byte attributes = computeAttributes(compressionType(), timestampType, isTransactional(), isControlBatch(), hasDeleteHorizonMs());
379:         buffer.putShort(ATTRIBUTES_OFFSET, attributes);
380:         buffer.putLong(MAX_TIMESTAMP_OFFSET, maxTimestamp);
381:         long crc = computeChecksum();
382:         ByteUtils.writeUnsignedInt(buffer, CRC_OFFSET, crc);
383:     }
384: 
385:     @Override
386:     public void setPartitionLeaderEpoch(int epoch) {
387:         buffer.putInt(PARTITION_LEADER_EPOCH_OFFSET, epoch);
388:     }
389: 
390:     @Override
391:     public long checksum() {
392:         return ByteUtils.readUnsignedInt(buffer, CRC_OFFSET);
393:     }
394: 
395:     public boolean isValid() {
396:         return sizeInBytes() >= RECORD_BATCH_OVERHEAD && checksum() == computeChecksum();
397:     }
398: 
399:     private long computeChecksum() {
400:         return Crc32C.compute(buffer, ATTRIBUTES_OFFSET, buffer.limit() - ATTRIBUTES_OFFSET);
401:     }
402: 
403:     private byte attributes() {
404:         // note we're not using the second byte of attributes
405:         return (byte) buffer.getShort(ATTRIBUTES_OFFSET);
406:     }
407: 
408:     @Override
409:     public boolean equals(Object o) {
410:         if (this == o)
411:             return true;
412:         if (o == null || getClass() != o.getClass())
413:             return false;
414: 
415:         DefaultRecordBatch that = (DefaultRecordBatch) o;
416:         return Objects.equals(buffer, that.buffer);
417:     }
418: 
419:     @Override
420:     public int hashCode() {
421:         return buffer != null ? buffer.hashCode() : 0;
422:     }
423: 
424:     private static byte computeAttributes(CompressionType type, TimestampType timestampType,
425:                                           boolean isTransactional, boolean isControl, boolean isDeleteHorizonSet) {
426:         if (timestampType == TimestampType.NO_TIMESTAMP_TYPE)
427:             throw new IllegalArgumentException("Timestamp type must be provided to compute attributes for message " +
428:                     "format v2 and above");
429: 
430:         byte attributes = isTransactional ? TRANSACTIONAL_FLAG_MASK : 0;
431:         if (isControl)
432:             attributes |= CONTROL_FLAG_MASK;
433:         if (type.id > 0)
434:             attributes |= (byte) (COMPRESSION_CODEC_MASK & type.id);
435:         if (timestampType == TimestampType.LOG_APPEND_TIME)
436:             attributes |= TIMESTAMP_TYPE_MASK;
437:         if (isDeleteHorizonSet)
438:             attributes |= DELETE_HORIZON_FLAG_MASK;
439:         return attributes;
440:     }
441: 
442:     public static void writeEmptyHeader(ByteBuffer buffer,
443:                                         byte magic,
444:                                         long producerId,
445:                                         short producerEpoch,
446:                                         int baseSequence,
447:                                         long baseOffset,
448:                                         long lastOffset,
449:                                         int partitionLeaderEpoch,
450:                                         TimestampType timestampType,
451:                                         long timestamp,
452:                                         boolean isTransactional,
453:                                         boolean isControlRecord) {
454:         int offsetDelta = (int) (lastOffset - baseOffset);
455:         writeHeader(buffer, baseOffset, offsetDelta, DefaultRecordBatch.RECORD_BATCH_OVERHEAD, magic,
456:                     CompressionType.NONE, timestampType, RecordBatch.NO_TIMESTAMP, timestamp, producerId,
457:                     producerEpoch, baseSequence, isTransactional, isControlRecord, false, partitionLeaderEpoch, 0);
458:     }
459: 
460:     public static void writeHeader(ByteBuffer buffer,
461:                                    long baseOffset,
462:                                    int lastOffsetDelta,
463:                                    int sizeInBytes,
464:                                    byte magic,
465:                                    CompressionType compressionType,
466:                                    TimestampType timestampType,
467:                                    long baseTimestamp,
468:                                    long maxTimestamp,
469:                                    long producerId,
470:                                    short epoch,
471:                                    int sequence,
472:                                    boolean isTransactional,
473:                                    boolean isControlBatch,
474:                                    boolean isDeleteHorizonSet,
475:                                    int partitionLeaderEpoch,
476:                                    int numRecords) {
477:         if (magic < RecordBatch.CURRENT_MAGIC_VALUE)
478:             throw new IllegalArgumentException("Invalid magic value " + magic);
479:         if (baseTimestamp < 0 && baseTimestamp != NO_TIMESTAMP)
480:             throw new IllegalArgumentException("Invalid message timestamp " + baseTimestamp);
481: 
482:         short attributes = computeAttributes(compressionType, timestampType, isTransactional, isControlBatch, isDeleteHorizonSet);
483: 
484:         int position = buffer.position();
485:         buffer.putLong(position + BASE_OFFSET_OFFSET, baseOffset);
486:         buffer.putInt(position + LENGTH_OFFSET, sizeInBytes - LOG_OVERHEAD);
487:         buffer.putInt(position + PARTITION_LEADER_EPOCH_OFFSET, partitionLeaderEpoch);
488:         buffer.put(position + MAGIC_OFFSET, magic);
489:         buffer.putShort(position + ATTRIBUTES_OFFSET, attributes);
490:         buffer.putLong(position + BASE_TIMESTAMP_OFFSET, baseTimestamp);
491:         buffer.putLong(position + MAX_TIMESTAMP_OFFSET, maxTimestamp);
492:         buffer.putInt(position + LAST_OFFSET_DELTA_OFFSET, lastOffsetDelta);
493:         buffer.putLong(position + PRODUCER_ID_OFFSET, producerId);
494:         buffer.putShort(position + PRODUCER_EPOCH_OFFSET, epoch);
495:         buffer.putInt(position + BASE_SEQUENCE_OFFSET, sequence);
496:         buffer.putInt(position + RECORDS_COUNT_OFFSET, numRecords);
497:         long crc = Crc32C.compute(buffer, ATTRIBUTES_OFFSET, sizeInBytes - ATTRIBUTES_OFFSET);
498:         buffer.putInt(position + CRC_OFFSET, (int) crc);
499:         buffer.position(position + RECORD_BATCH_OVERHEAD);
500:     }
501: 
502:     @Override
503:     public String toString() {
504:         return "RecordBatch(magic=" + magic() + ", offsets=[" + baseOffset() + ", " + lastOffset() + "], " +
505:                 "sequence=[" + baseSequence() + ", " + lastSequence() + "], " +
506:                 "partitionLeaderEpoch=" + partitionLeaderEpoch() + ", " +
507:                 "isTransactional=" + isTransactional() + ", isControlBatch=" + isControlBatch() + ", " +
508:                 "compression=" + compressionType() + ", timestampType=" + timestampType() + ", crc=" + checksum() + ")";
509:     }
510: 
511:     public static int sizeInBytes(long baseOffset, Iterable<Record> records) {
512:         Iterator<Record> iterator = records.iterator();
513:         if (!iterator.hasNext())
514:             return 0;
515: 
516:         int size = RECORD_BATCH_OVERHEAD;
517:         Long baseTimestamp = null;
518:         while (iterator.hasNext()) {
519:             Record record = iterator.next();
520:             int offsetDelta = (int) (record.offset() - baseOffset);
521:             if (baseTimestamp == null)
522:                 baseTimestamp = record.timestamp();
523:             long timestampDelta = record.timestamp() - baseTimestamp;
524:             size += DefaultRecord.sizeInBytes(offsetDelta, timestampDelta, record.key(), record.value(),
525:                     record.headers());
526:         }
527:         return size;
528:     }
529: 
530:     public static int sizeInBytes(Iterable<SimpleRecord> records) {
531:         Iterator<SimpleRecord> iterator = records.iterator();
532:         if (!iterator.hasNext())
533:             return 0;
534: 
535:         int size = RECORD_BATCH_OVERHEAD;
536:         int offsetDelta = 0;
537:         Long baseTimestamp = null;
538:         while (iterator.hasNext()) {
539:             SimpleRecord record = iterator.next();
540:             if (baseTimestamp == null)
541:                 baseTimestamp = record.timestamp();
542:             long timestampDelta = record.timestamp() - baseTimestamp;
543:             size += DefaultRecord.sizeInBytes(offsetDelta++, timestampDelta, record.key(), record.value(),
544:                     record.headers());
545:         }
546:         return size;
547:     }
548: 
549:     /**
550:      * Get an upper bound on the size of a batch with only a single record using a given key and value. This
551:      * is only an estimate because it does not take into account additional overhead from the compression
552:      * algorithm used.
553:      */
554:     static int estimateBatchSizeUpperBound(ByteBuffer key, ByteBuffer value, Header[] headers) {
555:         return RECORD_BATCH_OVERHEAD + DefaultRecord.recordSizeUpperBound(key, value, headers);
556:     }
557: 
558:     public static int incrementSequence(int sequence, int increment) {
559:         if (sequence > Integer.MAX_VALUE - increment)
560:             return increment - (Integer.MAX_VALUE - sequence) - 1;
561:         return sequence + increment;
562:     }
563: 
564:     public static int decrementSequence(int sequence, int decrement) {
565:         if (sequence < decrement)
566:             return Integer.MAX_VALUE - (decrement - sequence) + 1;
567:         return sequence - decrement;
568:     }
569: 
570:     // visible for testing
571:     abstract class RecordIterator implements CloseableIterator<Record> {
572:         private final Long logAppendTime;
573:         private final long baseOffset;
574:         private final long baseTimestamp;
575:         private final int baseSequence;
576:         private final int numRecords;
577:         private int readRecords = 0;
578: 
579:         RecordIterator() {
580:             this.logAppendTime = timestampType() == TimestampType.LOG_APPEND_TIME ? maxTimestamp() : null;
581:             this.baseOffset = baseOffset();
582:             this.baseTimestamp = baseTimestamp();
583:             this.baseSequence = baseSequence();
584:             int numRecords = count();
585:             if (numRecords < 0)
586:                 throw new InvalidRecordException("Found invalid record count " + numRecords + " in magic v" +
587:                         magic() + " batch");
588:             this.numRecords = numRecords;
589:         }
590: 
591:         @Override
592:         public boolean hasNext() {
593:             return readRecords < numRecords;
594:         }
595: 
596:         @Override
597:         public Record next() {
598:             if (readRecords >= numRecords)
599:                 throw new NoSuchElementException();
600: 
601:             readRecords++;
602:             Record rec = readNext(baseOffset, baseTimestamp, baseSequence, logAppendTime);
603:             if (readRecords == numRecords) {
604:                 // Validate that the actual size of the batch is equal to declared size
605:                 // by checking that after reading declared number of items, there no items left
606:                 // (overflow case, i.e. reading past buffer end is checked elsewhere).
607:                 if (!ensureNoneRemaining())
608:                     throw new InvalidRecordException("Incorrect declared batch size, records still remaining in file");
609:             }
610:             return rec;
611:         }
612: 
613:         protected abstract Record readNext(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime);
614: 
615:         protected abstract boolean ensureNoneRemaining();
616: 
617:         @Override
618:         public void remove() {
619:             throw new UnsupportedOperationException();
620:         }
621: 
622:     }
