            builder.appendSnapshotHeaderMessage(timestamp, snapshotHeaderRecord);
            return builder.build();
        }
    }

    /**
     * Create {@code MemoryRecords} with a snapshot footer record.
     *
     * @param initialOffset The base offset
     * @param timestamp The timestamp for the record
     * @param leaderEpoch The leader epoch
     * @param buffer The buffer to write to
     * @param snapshotFooterRecord The snapshot footer record
     * @return {@code MemoryRecords} containing the record
     */
    public static MemoryRecords withSnapshotFooterRecord(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer,
        SnapshotFooterRecord snapshotFooterRecord
    ) {
        try (MemoryRecordsBuilder builder = createKraftControlRecordBuilder(
                initialOffset,
                timestamp,
                leaderEpoch,
